def self_refine_smart(spec: str, pass_threshold: int = 8, max_rounds: int = 4) -> dict:
    """
    Refined control logic: stop when threshold met OR no improvement for 1 round.
    """
    feedback = None
    history = []
    prev_score = 0

    for round_num in range(1, max_rounds + 1):
        code = generate(spec, feedback)
        evaluation = critique(spec, code)
        score = evaluation.get("score", 0)

        history.append({"round": round_num, "score": score, "code": code})

        # Exit 1: threshold met
        if score >= pass_threshold:
            return {"status": "threshold_met", "rounds": round_num,
                    "final_code": code, "final_score": score}

        # Exit 2: no improvement from previous round (stuck)
        if round_num > 1 and score <= prev_score:
            best = max(history, key=lambda h: h["score"])
            return {"status": "no_improvement", "rounds": round_num,
                    "final_code": best["code"], "final_score": best["score"]}

        prev_score = score
        feedback = evaluation.get("feedback", "")

    best = max(history, key=lambda h: h["score"])
    return {"status": "max_rounds", "rounds": max_rounds,
            "final_code": best["code"], "final_score": best["score"]}

import anthropic
import json

client = anthropic.Anthropic()

JSON_GENERATOR_SYSTEM = """
You convert natural language event descriptions into JSON.
Return only valid JSON matching this schema:
{
  "event_name": string,
  "date": "YYYY-MM-DD",
  "location": {"city": string, "country": string},
  "attendee_count": integer >= 0
}
"""

def generate_json(description: str, feedback: str | None = None) -> str:
    user_msg = description
    if feedback:
        user_msg += f"\n\nPrevious output was invalid. Issues:\n{feedback}\n\nFix and retry."
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        system=JSON_GENERATOR_SYSTEM,
        messages=[{"role": "user", "content": user_msg}],
    )
    return resp.content[0].text.strip()

def validate_event_json(raw: str) -> dict:
    """Rule-based validator — no LLM call needed."""
    try:
        obj = json.loads(raw)
    except json.JSONDecodeError as e:
        return {"passes": False, "issues": [f"Invalid JSON: {e}"]}

    issues = []
    for field in ("event_name", "date", "location", "attendee_count"):
        if field not in obj:
            issues.append(f"Missing field: {field}")
    if "date" in obj:
        import re
        if not re.match(r"^\d{4}-\d{2}-\d{2}$", str(obj.get("date", ""))):
            issues.append("date must be YYYY-MM-DD format")
    if "attendee_count" in obj and not isinstance(obj["attendee_count"], int):
        issues.append("attendee_count must be an integer")
    if "location" in obj and isinstance(obj["location"], dict):
        for k in ("city", "country"):
            if k not in obj["location"]:
                issues.append(f"Missing location.{k}")

    return {"passes": len(issues) == 0, "issues": issues}

def refine_json_output(description: str, max_rounds: int = 3) -> dict:
    """
    Rule-based critique + LLM generator.
    No LLM call for the critic — validation is deterministic.
    """
    feedback = None
    for round_num in range(1, max_rounds + 1):
        raw = generate_json(description, feedback)
        result = validate_event_json(raw)
        if result["passes"]:
            return {"status": "passed", "rounds": round_num, "output": json.loads(raw)}
        feedback = "\n".join(result["issues"])
    return {"status": "max_rounds", "rounds": max_rounds, "last_output": raw, "issues": feedback}

description = "PyCon 2025 in Prague, Czech Republic, 1200 attendees, on the 14th of May 2025"
result = refine_json_output(description)
print(result)
